SELECT 
FROM industry_trend_stat
WHERE industry_name = #{industryName}
  AND trade_date BETWEEN #{startDate} AND #{endDate}
ORDER BY trade_date ASC, stat_period ASC

SELECT 
FROM industry_trend_stat
WHERE industry_name = #{industryName}
  AND trade_date = #{tradeDate}
  AND stat_period = #{statPeriod}

SELECT 
FROM industry_trend_stat
WHERE trade_date = #{tradeDate}
  AND stat_period = #{statPeriod}
ORDER BY trend_slope DESC
